    max_state = max(state_counts, key=state_counts.get)
    max_count = state_counts[max_state]
    ratings_list = state_ratings[max_state]
    avg_rating = sum(ratings_list) / len(ratings_list) if ratings_list else 0

    result = {
        "state": max_state,
        "wifi_business_count": max_count,
        "average_rating": avg_rating
    }

print("__RESULT__:")
